namespace sv_452d066ae526432493f7f78944aab105.Services;

public class AppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Williams",
            "Dr. Patel"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        return Task.FromResult(new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        });
    }

    /// <summary>
    /// Validates patient info server-side. Returns a dictionary of field name to error message.
    /// An empty dictionary means validation passed.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors["Email"] = "Account has outstanding balance";
        }

        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            errors["Doctor"] = "Selected doctor does not accept self-pay patients";
        }

        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            errors["TimeSlot"] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_452d066ae526432493f7f78944aab105.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book an Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />

    @* ── STEP 1 ── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (serverErrors.TryGetValue("Email", out var emailError))
            {
                <div class="validation-message">@emailError</div>
            }
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
        }
    </fieldset>

    @* ── STEP 2 ── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (serverErrors.TryGetValue("Doctor", out var doctorError))
                {
                    <div class="validation-message">@doctorError</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeslot">Time Slot</label>
                @if (timeSlots.Count == 0 && !string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
                {
                    <p class="text-muted">Loading time slots…</p>
                }
                <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot" @bind-Value:after="ClearTimeSlotServerError">
                    <option value="">-- Select --</option>
                    @foreach (var slot in timeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (serverErrors.TryGetValue("TimeSlot", out var timeSlotError))
                {
                    <div class="validation-message">@timeSlotError</div>
                }
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3" @bind-Value="Model.ReasonForVisit" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-outline-secondary me-2" @onclick="LoadTimeSlots">
                Refresh Time Slots
            </button>
            <button type="button" class="btn btn-info me-2" @onclick="CheckAvailability" disabled="@isChecking">
                @(isChecking ? "Checking…" : "Check Availability")
            </button>
            <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked || serverErrors.Count > 0)">
                Book Appointment
            </button>
        </fieldset>
    }
</EditForm>

@if (isBooked)
{
    <div class="alert alert-success mt-4" role="alert">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentFormModel Model { get; set; } = new();
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();
    private bool showStep2;
    private bool isChecking;
    private bool availabilityChecked;
    private bool isBooked;

    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        editContext.EnableDataAnnotationsValidation();

        // Validate only step-1 fields
        var isValid = editContext.Validate();
        // Step 1 fields will be valid if DataAnnotations pass; step 2 fields have no value yet
        // but they are not required to proceed—only step-1 fields matter here.
        // Since step-2 fields start null/empty and are [Required], full Validate() would fail.
        // Instead, manually check step-1 fields.
        var step1Valid =
            !string.IsNullOrWhiteSpace(Model.PatientName) &&
            !string.IsNullOrWhiteSpace(Model.Email) &&
            new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email) &&
            !string.IsNullOrWhiteSpace(Model.Phone) &&
            !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

        if (step1Valid)
        {
            showStep2 = true;
        }
        else
        {
            // Trigger validation messages so the user sees what's missing
            editContext.Validate();
        }
    }

    private async Task LoadTimeSlots()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor,
                DateOnly.FromDateTime(Model.AppointmentDate.Value));
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityChecked = false;

        // Ensure step 2 fields are filled
        editContext = new EditContext(Model);
        editContext.EnableDataAnnotationsValidation();
        if (!editContext.Validate())
        {
            return;
        }

        isChecking = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.Doctor,
                Model.TimeSlot);

            if (errors.Count > 0)
            {
                serverErrors = errors;
            }
            else
            {
                availabilityChecked = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private void ClearTimeSlotServerError()
    {
        serverErrors.Remove("TimeSlot");
        availabilityChecked = false;
    }

    private void HandleSubmit()
    {
        if (serverErrors.Count == 0 && availabilityChecked)
        {
            isBooked = true;
        }
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_452d066ae526432493f7f78944aab105.Components.Pages;

public class AppointmentFormModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = "";

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Enter a valid email address.")]
    public string Email { get; set; } = "";

    [Required(ErrorMessage = "Phone number is required.")]
    public string Phone { get; set; } = "";

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = "";

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string Doctor { get; set; } = "";

    [Required(ErrorMessage = "Appointment date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = "";

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string ReasonForVisit { get; set; } = "";
}

public class FutureDateAttribute : ValidationAttribute
{
    public override bool IsValid(object? value)
    {
        if (value is DateTime dt)
        {
            return dt.Date > DateTime.Today;
        }
        return false;
    }
}

