    private AppointmentFormModel Model { get; set; } = new();
    private List<string> doctors = new();
    private List<string> timeSlots = new();
    private Dictionary<string, string> serverErrors = new();
    private bool showStep2;
    private bool isChecking;
    private bool availabilityChecked;
    private bool isBooked;

    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        editContext = new EditContext(Model);
        editContext.EnableDataAnnotationsValidation();

        // Validate only step-1 fields
        var isValid = editContext.Validate();
        // Step 1 fields will be valid if DataAnnotations pass; step 2 fields have no value yet
        // but they are not required to proceed—only step-1 fields matter here.
