    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor,
                DateOnly.FromDateTime(Model.AppointmentDate.Value));
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityChecked = false;

        // Ensure step 2 fields are filled
        editContext = new EditContext(Model);
        editContext.EnableDataAnnotationsValidation();
        if (!editContext.Validate())
        {
            return;
        }

        isChecking = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.Doctor,
                Model.TimeSlot);

            if (errors.Count > 0)
            {
                serverErrors = errors;
            }
            else
            {
                availabilityChecked = true;
            }
        }
        finally
        {
            isChecking = false;
        }
    }

    private void ClearTimeSlotServerError()
    {
        serverErrors.Remove("TimeSlot");
        availabilityChecked = false;
    }

    private void HandleSubmit()
    {
        if (serverErrors.Count == 0 && availabilityChecked)
        {
            isBooked = true;
        }
    }
}
"}

